import React from "react";

const DashboardLayout = ({ children }) => {
  return (
    <div className="dashboard">
      {/* Main content */}
      {children}

      {/* Floating Action Button */}
      <button
        className="fixed bottom-8 right-8 w-14 h-14 rounded-xl bg-blue-500 text-white flex items-center justify-center shadow-lg"
        title="Quick Action"
      >
        ⚡
      </button>
    </div>
  );
};

export default DashboardLayout;
